C = (0,5);
D = (1,2);

draw((-10,0)--(10,0));
draw((0,-10)--(0,10));
draw(A--B,red);
draw(V--P,dashed);
draw(C--V,Arrow(6));
draw(C--P,Arrow(6));

dot("$(-4,-2)$", V, SW);
dot("$(0,5)$", C, E);
dot("$\begin{pmatrix} \frac{17}{10} \\ -\frac{51}{10} \end{pmatrix}$", P, NE);
[/asy]

